/* Convert a character to uppercase */
int to_upper(int c) {
    if (c >= 97 && c <= 122) {
        return c - 32;
    }
    return c;
}

/* Case-insensitive string comparison */
int str_eq_nocase(char *a, char *b) {
    while (*a && *b) {
        if (to_upper(*a) != to_upper(*b)) {
            return 0;
